import{_ as a,o as t,c as o,aA as i}from"./chunks/framework.CAIZw9CR.js";const u=JSON.parse('{"title":"LLM and agent context","description":"","frontmatter":{},"headers":[],"relativePath":"llms.md","filePath":"llms.md","lastUpdated":null}'),r={name:"llms.md"};function n(l,e,c,s,p,d){return t(),o("div",null,[...e[0]||(e[0]=[i('<h1 id="LLM-and-agent-context" tabindex="-1">LLM and agent context <a class="header-anchor" href="#LLM-and-agent-context" aria-label="Permalink to &quot;LLM and agent context {#LLM-and-agent-context}&quot;">​</a></h1><p>Kraken ships a compact agent-oriented context at <code>/llms.txt</code> in the built site. It is intentionally stricter than a marketing page: it tells an agent what this branch can run, what it must not claim, and where the longer docs live.</p><h2 id="What-the-agent-should-know-first" tabindex="-1">What the agent should know first <a class="header-anchor" href="#What-the-agent-should-know-first" aria-label="Permalink to &quot;What the agent should know first {#What-the-agent-should-know-first}&quot;">​</a></h2><ul><li><p>Public workflow starts from <code>.krk</code> files.</p></li><li><p>Main entry point: <code>run_simulation(&quot;examples/cavity.krk&quot;)</code>.</p></li><li><p>Parsed setup entry point: <code>setup = load_kraken(&quot;file.krk&quot;)</code>; <code>run_simulation(setup)</code>.</p></li><li><p>File-path <code>run_simulation</code> accepts <code>max_steps</code> and parser kwargs.</p></li><li><p>Parsed-setup <code>run_simulation(setup)</code> does not accept <code>max_steps</code>.</p></li><li><p>v0.1.0 public physics: BGK single-phase, Guo forcing, thermal DDF, Boussinesq natural convection.</p></li><li><p>Not public in this branch: MRT, axisymmetric, grid refinement, VOF, phase-field, Shan-Chen, species, rheology, viscoelasticity, SLBM.</p></li></ul><h2 id="Result-policy" tabindex="-1">Result policy <a class="header-anchor" href="#Result-policy" aria-label="Permalink to &quot;Result policy {#Result-policy}&quot;">​</a></h2><p>An agent should cite only benchmark values that are either on <a href="./benchmarks/accuracy">Accuracy</a>, <a href="./benchmarks/performance">Performance</a>, or backed by a committed CSV in <code>benchmarks/results/</code>.</p><p>The currently rerun convergence checks are:</p><ul><li><p>Poiseuille: order 2.00.</p></li><li><p>Taylor-Green: order 1.99/2.00/2.00.</p></li><li><p>Thermal conduction: order 1.00 with the current wall treatment.</p></li><li><p>Natural convection <code>Ra = 1e3</code>, <code>N = 64</code>: <code>Nu = 1.1423</code>, error <code>2.17%</code>.</p></li></ul><h2 id="Long-form-references" tabindex="-1">Long-form references <a class="header-anchor" href="#Long-form-references" aria-label="Permalink to &quot;Long-form references {#Long-form-references}&quot;">​</a></h2><ul><li><p><a href="./getting_started">Getting started</a></p></li><li><p><a href="./capabilities">Capabilities</a></p></li><li><p><a href="./integration_roadmap">Integration roadmap</a></p></li><li><p><a href="./krk/overview">.krk overview</a></p></li><li><p><a href="./api/public_api">Public API inventory</a></p></li><li><p><a href="./julia_docs">Julia ecosystem docs</a></p></li></ul>',10)])])}const m=a(r,[["render",n]]);export{u as __pageData,m as default};
